function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;

    // Precompute teleportList
    const teleportList = new Array(m);
    for (let i = 0; i < m; i++) {
        teleportList[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            teleportList[i][j] = [];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j]) {
                        teleportList[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    // Dijkstra's algorithm
    const dist = new Array(m);
    for (let i = 0; i < m; i++) {
        dist[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            dist[i][j] = new Array(k + 1).fill(Infinity);
        }
    }
    dist[0][0][0] = 0;

    // Priority queue
    const heap = [];
    heap.push([0, 0, 0, 0]);

    // Helper functions for heap
    function push(heap, value) {
        heap.push(value);
        let i = heap.length - 1;
        while (i > 0) {
            const parent = Math.floor((i - 1) / 2);
            if (heap[parent][0] <= heap[i][0]) break;
            [heap[i], heap[parent]] = [heap[parent], heap[i]];
            i = parent;
        }
    }

    function pop(heap) {
        if (heap.length === 0) return null;
        const val = heap[0];
        heap[0] = heap[heap.length - 1];
        heap.pop();
        let i = 0;
        while (true) {
            const left = 2 * i + 1;
            const right = 2 * i + 2;
            let smallest = i;
            if (left < heap.length && heap[left][0] < heap[smallest][0]) smallest = left;
            if (right < heap.length && heap[right][0] < heap[smallest][0]) smallest = right;
            if (smallest === i) break;
            [heap[i], heap[smallest]] = [heap[smallest], heap[i]];
            i = smallest;
        }
        return val;
    }

    while (heap.length > 0) {
        const [cost, i, j, t] = pop(heap);
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dist[i][j][t]) {
            continue;
        }

        // Regular moves
        if (j + 1 < n) {
            const new_i = i;
            const new_j = j + 1;
            const new_t = t;
            const new_cost = cost + grid[new_i][new_j];
            if (new_cost < dist[new_i][new_j][new_t]) {
                dist[new_i][new_j][new_t] = new_cost;
                push(heap, [new_cost, new_i, new_j, new_t]);
            }
        }
        if (i + 1 < m) {
            const new_i = i + 1;
            const new_j = j;
            const new_t = t;
            const new_cost = cost + grid[new_i][new_j];
            if (new_cost < dist[new_i][new_j][new_t]) {
                dist[new_i][new_j][new_t] = new_cost;
                push(heap, [new_cost, new_i, new_j, new_t]);
            }
        }

        // Teleportation
        if (t < k) {
            for (const [x, y] of teleportList[i][j]) {
                const new_i = x;
                const new_j = y;
                const new_t = t + 1;
                const new_cost = cost;
                if (new_cost < dist[new_i][new_j][new_t]) {
                    dist[new_i][new_j][new_t] = new_cost;
                    push(heap, [new_cost, new_i, new_j, new_t]);
                }
            }
        }
    }

    return -1;
}

